import sys

class Solution:
    def flipBitsToMask(self, mask: int, target: int) -> int:
        flipCount = 0
        for i in range(31):
            if ((1 << i) & mask) != 0:
                flipCount += (mask & (1 << i) != 0) and 1 or 0
        for i in range(31):
            if ((1 << i) & mask) == 0:
                flipCount += (target & (1 << i) != 0) and 1 or 0
        return flipCount

if __name__ == '__main__':
    mask = int(sys.stdin.readline().strip())
    target = int(sys.stdin.readline().strip())
    solution = Solution()
    print(solution.flipBitsToMask(mask, target))

