#include <iostream>
using namespace std;

class Solution {
    public:
    int flipBitsToMask(int mask, int target) {
        int flipCount = 0;
        for (int i = 0; i < 31; i++) {
            if (((1 << i) & mask) != 0) {
                flipCount += (mask & (1 << i) != 0) ? 1 : 0;
            }
        }
        for (int i = 0; i < 31; i++) {
            if (((1 << i) & mask) == 0) {
                flipCount += (target & (1 << i) != 0) ? 1 : 0;
            }
        }
        return flipCount;
    };
};

int main(){
    int mask, target;
    cin >> mask >> target;
    Solution s;
    cout << s.flipBitsToMask(mask, target);
    return 0;
}
